from typing import TypedDict, Literal, Annotated
import operator
from langgraph.graph import StateGraph, END

class CyclicState(TypedDict):
    task: str
    draft: str
    score: float
    feedback: str
    iterations: int
    score_history: Annotated[list[float], operator.add]  # accumulate across cycles

def generate(state: CyclicState) -> dict:
    prompt = state["task"]
    if state.get("feedback"):
        prompt += f"\n\nPrevious attempt score: {state['score']:.2f}\nFeedback: {state['feedback']}"
    draft = writer_llm.invoke(prompt)
    return {"draft": draft.content, "iterations": state["iterations"] + 1}

def evaluate(state: CyclicState) -> dict:
    result = critic_llm.with_structured_output(EvalResult).invoke(state["draft"])
    return {
        "score": result.score,
        "feedback": result.feedback,
        "score_history": [result.score],   # appended via Annotated reducer
    }

def should_continue(state: CyclicState) -> Literal["generate", "refine"]:
    if state["score"] >= 0.85:
        return "refine"          # quality threshold met → exit cycle
    if state["iterations"] >= 4:
        return "refine"          # hard cap → exit regardless of quality
    return "generate"            # back-edge: loop again

def refine(state: CyclicState) -> dict:
    polished = format_llm.invoke(state["draft"])
    return {"draft": polished.content}

builder = StateGraph(CyclicState)
builder.add_node("generate", generate)
builder.add_node("evaluate", evaluate)
builder.add_node("refine",   refine)

builder.set_entry_point("generate")
builder.add_edge("generate", "evaluate")
builder.add_conditional_edges("evaluate", should_continue, {
    "generate": "generate",   # back-edge — creates the cycle
    "refine":   "refine",
})
builder.add_edge("refine", END)
graph = builder.compile()

from typing import Annotated
import operator

class RichCyclicState(TypedDict):
    task: str
    draft: str
    score: float
    feedback: str
    iterations: int
    all_drafts: Annotated[list[str], operator.add]      # every draft ever produced
    all_feedback: Annotated[list[str], operator.add]    # every feedback string

def generate_with_history(state: RichCyclicState) -> dict:
    history_text = ""
    if state.get("all_feedback"):
        history_text = "\n\nPrevious attempts and feedback:"
        for i, (d, fb) in enumerate(zip(state["all_drafts"], state["all_feedback"]), 1):
            history_text += f"\n[Attempt {i}] Score {state['score']:.2f}: {fb[:120]}"

    draft = writer_llm.invoke(state["task"] + history_text)
    return {
        "draft": draft.content,
        "all_drafts": [draft.content],    # appended via reducer
        "iterations": state["iterations"] + 1,
    }

def evaluate_with_history(state: RichCyclicState) -> dict:
    result = critic_llm.with_structured_output(EvalResult).invoke(state["draft"])
    return {
        "score": result.score,
        "feedback": result.feedback,
        "all_feedback": [result.feedback],  # appended via reducer
    }
